// Auth: URL token from process.env ($vars is Enterprise-only; process.env works on community)
// Token set in n8n Docker env as FUB_SOCIAL_WEBHOOK_TOKEN (in docker-compose.yml environment section).
// Requires n8n container restart to activate — run: sudo docker stop n8n && sudo docker start n8n
const crypto = require('crypto');
const EXPECTED = process.env.FUB_SOCIAL_WEBHOOK_TOKEN;
if (!EXPECTED) throw new Error('FUB_SOCIAL_WEBHOOK_TOKEN not configured in n8n environment');
const incoming = $input.first().json.query?.token ?? '';
if (incoming.length !== EXPECTED.length) throw new Error('Invalid token');
if (!crypto.timingSafeEqual(Buffer.from(incoming), Buffer.from(EXPECTED))) throw new Error('Invalid token');

// Sanitize FUB fields before LLM interpolation (prompt injection mitigation)
function sanitize(s, maxLen) {
  return String(s ?? '').replace(/[^\w\s,.$#@!&()/'.-]/g, '').trim().slice(0, maxLen);
}

// Extract deal stage from FUB payload
const payload = $input.first().json.body ?? {};
const stage = (payload.deal?.stage ?? payload.stage ?? payload.deals?.[0]?.stage ?? '').toLowerCase();
const agentEmail = payload.agent?.email ?? payload.deal?.agent?.email ?? '';
const prop = payload.deal?.property ?? payload.property ?? payload.deals?.[0]?.property ?? {};

const isUC   = /under.?contract|in.?contract/i.test(stage);
const isSold = /closed|sold|settlement/i.test(stage);

return [{ json: {
  stage, isUC, isSold,
  skip: !isUC && !isSold,
  address: sanitize(prop.address ?? 'Address TBD', 120),
  city:    sanitize(prop.city ?? 'Palm Coast', 60),
  price:   sanitize(String(prop.price ?? payload.deal?.value ?? ''), 20),
  beds:    sanitize(String(prop.bedrooms ?? ''), 5),
  baths:   sanitize(String(prop.bathrooms ?? ''), 5),
  agent:   sanitize(payload.agent?.name ?? 'the team', 80),
  agentEmail
}}];

const crypto = require('crypto');
const raw = $input.first().json.choices[0].message.content;
const prev = $('Auth + Extract Stage').first().json;
function esc(s){return String(s??'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');}
function extract(label){
  const r = new RegExp(label+':?\\s*([\\s\\S]*?)(?=(?:COASTAL:|FAMILY:|LUXURY:|$))','i');
  const m = raw.match(r); return m?m[1].trim():'';
}
const drafts=[
  {tone:'Coastal',content:extract('COASTAL')},
  {tone:'Family',content:extract('FAMILY')},
  {tone:'Luxury',content:extract('LUXURY')}
].filter(d=>d.content);
return drafts.map(d=>({json:{token:crypto.randomUUID(),workflow:'under-contract',tone:d.tone,content:d.content,address:esc(prev.address),city:esc(prev.city),agent:esc(prev.agent),agentEmail:prev.agentEmail}}));

